### RxDB Replication Setup (JavaScript)

Source: https://github.com/pubkey/rxdb/blob/master/docs/articles/zero-latency-local-first.html

Configures replication for an RxDB collection, allowing it to sync with a remote server. It defines pull and push handlers for synchronizing data, enabling live replication with a specified retry time for handling errors and disconnections.

```javascript
import { replicateRxCollection } from 'rxdb/plugins/replication';

async function syncLocalTasks(db) {
  replicateRxCollection({
    collection: db.tasks,
    replicationIdentifier: 'sync-tasks',
    // Define how to pull server documents and push local documents
    pull: {
      handler: async (lastCheckpoint, batchSize) => {
        // logic to retrieve updated tasks from the server since lastCheckpoint
      },
    },
    push: {
      handler: async (docs) => {
        // logic to post local changes to the server
      },
    },
    live: true,        // continuously replicate
    retryTime: 5000,   // retry on errors or disconnections
  });
}
```

